import pytest

EXACT_LIMIT_BYTES = 10 * 1024 * 1024

def test_upload_file_at_exact_10mb_boundary_is_accepted(
    auth_headers, make_upload_file, api_client
):
    file_bytes = make_upload_file(
        size_bytes=EXACT_LIMIT_BYTES, mime="application/pdf"
    )
    files = {"file": ("boundary.pdf", file_bytes, "application/pdf")}

    resp = api_client.post(
        "/documents/upload",
        files=files,
        headers=auth_headers,
    )

    assert resp.status_code == 201, (
        f"Exact-limit file must be accepted; got {resp.status_code}"
    )
    body = resp.json()
    assert body.get("document_id"), "document_id must be present for boundary upload"

import pytest

@pytest.mark.parametrize("mime,filename", [
    ("text/plain", "doc.txt"),
    ("application/zip", "doc.zip"),
    ("image/gif", "doc.gif"),
])
def test_upload_unsupported_mime_type_returns_415(
    auth_headers, make_upload_file, api_client, mime, filename
):
    file_bytes = make_upload_file(size_bytes=1024, mime=mime)
    files = {"file": (filename, file_bytes, mime)}

    resp = api_client.post(
        "/documents/upload",
        files=files,
        headers=auth_headers,
    )

    assert resp.status_code == 415, f"Expected 415 for {mime}, got {resp.status_code}"
    body = resp.json()
    assert "document_id" not in body, "document_id must not appear on MIME rejection"

import uuid
import pytest

def test_upload_idempotent_on_retry_returns_same_document_id(
    auth_headers, make_upload_file, api_client
):
    idempotency_key = str(uuid.uuid4())
    file_bytes = make_upload_file(size_bytes=500 * 1024, mime="image/png")
    headers = {**auth_headers, "Idempotency-Key": idempotency_key}

    def do_upload():
        files = {"file": ("onboarding.png", file_bytes, "image/png")}
        return api_client.post(
            "/documents/upload",
            files=files,
            headers=headers,
        )

    resp1 = do_upload()
    assert resp1.status_code in (200, 201), (
        f"First upload must succeed; got {resp1.status_code}"
    )
    doc_id_1 = resp1.json().get("document_id")
    assert doc_id_1, "document_id must be present on first upload"

    resp2 = do_upload()
    assert resp2.status_code in (200, 201), (
        f"Retry must succeed; got {resp2.status_code}"
    )
    doc_id_2 = resp2.json().get("document_id")
    assert doc_id_2 == doc_id_1, (
        f"Idempotent retry must return same document_id: {doc_id_1!r} != {doc_id_2!r}"
    )
